// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json = JSON.parse(item.json.data)
}
return $input.all();

const glob = $('Global Fields').first().json;
const items = $('Rename Keys').all().slice(0, parseInt(glob.number_question));
return items;

const output = $input.first().json.output;

let questions;

if (Array.isArray(output)) {
  // Déjà un tableau d'objets
  questions = output;
} else if (typeof output === 'object' && output !== null) {
  // Objet seul
  questions = [output];
} else if (typeof output === 'string') {
  // C'est un texte → on extrait le JSON
  const jsonMatch = output.match(/```json\n([\s\S]*?)\n```/) || 
                    output.match(/(\[[\s\S]*\])/);
  const jsonContent = jsonMatch ? jsonMatch[1] : output;
  questions = JSON.parse(jsonContent);
  if (!Array.isArray(questions)) questions = [questions];
} else {
  throw new Error(`Type inattendu : ${typeof output}`);
}

return questions.map(q => ({ json: q }));

// Iterate over each item in the input
const items = []
const questions = $("Generate Azure Speech prompting").all();
$input.all().forEach((item, i) => {
  // Map the segments array to keep only specific fields
  if (item.json && item.json.output && Array.isArray(item.json.output.segments)) {
    var segments = item.json.output.segments;

    // Ensure there are at least two segments to merge
    if (segments.length >= 3) {
      const last = segments[segments.length - 2];
      const secondLast = segments[segments.length - 1];

      // Create merged segment
      const mergedSegment = {
        id: last.id, // Keep the earlier id or use a new one
        start: last.start, // Use start of the earlier segment
        end: secondLast.end, // Use end of the last segment
        text: `${last.text} ${secondLast.text}`.trim() // Concatenate text
      };

      // Build new segments array: keep all except last two, then add merged
      const newSegments = segments.slice(0, -2); // Keep all but last two
      newSegments.push(mergedSegment); // Add merged segment
      segments = newSegments
    }

    const data = {};
    data.id = i + 1
    data.audio = item.json.input.audio
    data.image = questions[i].json.image_url
    data.question = questions[i].json.question
    data.option_a = questions[i].json.option_a
    data.option_b = questions[i].json.option_b
    data.option_c = questions[i].json.option_c
    data.option_d = questions[i].json.option_d
    data.correct_answer = questions[i].json.correct_answer
    data.category = questions[i].json.category
    data.remotion = segments.map(segment => ({
      id: segment.id,
      start: segment.start,
      end: segment.end,
      text: segment.text.trim()
    }));
    items.push(data);
  }
});

// Return the modified items
return items;

const questions = $('Get limited question').all();
return questions.map(item => ({
  json: {
    id: item.json.id,
  }
}));

const items = $input.all();

const results = await Promise.all(
  items.map(async (item, index) => {
    const buffer = await this.helpers.getBinaryDataBuffer(index, 'data');
    const mimeType = item.binary['data'].mimeType;
    const base64 = buffer.toString('base64');

    return {
      json: {
        img: {
          base64: `data:${mimeType};base64,${base64}`,
          fileName: item.binary['data'].fileName
        }
      }
    };
  })
);

return results;

const glob = $('Global Fields').first().json;

const escapeHtml = (str) => {
  if (!str) return '';
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
};

const audio_background = escapeHtml(glob.audio_background || '');
const audio_break = escapeHtml(glob.audio_break || '');
const audio_correct_answer = escapeHtml(glob.audio_correct_answer || '');

let i = 0;
const items = $input.all();

for (const item of items) {
  i++;
  let voice_script = '';

  voice_script += "<speak version='1.0' xml:lang='fr-FR'>";

  if (audio_background) {
    voice_script += `<mstts:backgroundaudio
        src='${audio_background}'
        volume='30' fadein='1500' fadeout='2000'/>`;
  }

  voice_script += "<voice xml:lang='fr-FR' xml:gender='Male' name='fr-FR-RemyMultilingualNeural'>";
  voice_script += "<p>";
  voice_script += item.json.question || '';

  if (true) {
    voice_script += `<audio src='${audio_break}'/>`;
  } else {
    voice_script += "<break time='5s'/>";
  }

  if (true) {
    voice_script += `<audio src='${audio_correct_answer}'/>`;
  }

  const correctAnswer = item.json.correct_answer || '';
  voice_script += `Réponse ${correctAnswer} `;
  voice_script += "<break strength='medium' />";

  const optionKey = `option_${correctAnswer.toLowerCase()}`;
  voice_script += item.json[optionKey] || '';

  voice_script += "</p>";
  voice_script += "</voice></speak>";

  item.json.voice_script = voice_script;
  item.json.audio_filename = (glob.aws_prefix_audio_file || '') + i + '.mp3';
  item.json.image_filename = (glob.aws_prefix_img_file || '') + i + '.png';
  item.json.audio_url = 'https://' + (glob.aws_bucket_name || '') + '.s3.' + (glob.aws_region || '') + '.amazonaws.com/audio/' + item.json.audio_filename;
  item.json.image_url = 'https://' + (glob.aws_bucket_name || '') + '.s3.' + (glob.aws_region || '') + '.amazonaws.com/image/' + item.json.image_filename;
}

return items;
